sql:
SELECT MAX(match_count) AS highest_number_of_matches
FROM (
  SELECT opponent_team_id, stadium_id, COUNT(match_id) AS match_count
  FROM matches
  GROUP BY opponent_team_id, stadium_id
) AS match_counts;

SELECT COUNT(DISTINCT opponent_team_id) AS total_number_of_teams
FROM matches
WHERE match_status = 'Completed' AND weather_conditions = 'Rainy';

